  /env\s*\(\s*["'][^"']*(DATABASE|DB|URL|POSTGRES|REDIS|MONGO|SQLITE|TURSO|LIBSQL|PLANETSCALE|NEON)[^"']*["']\s*\)/i,
  /(?:host|port|user|password|url|database|dbName|connectionString|datasource)\s*:\s*process\.env\.[A-Z_]+/i,
  /(?:DATABASE_URL|DB_URL|POSTGRES_URL|REDIS_URL|MONGO_URL|TURSO_URL|LIBSQL_URL|DATABASE_HOST|DB_HOST)\s*[:=]\s*/i,
  /\$\{(DATABASE_URL|DB_HOST|DB_NAME|DB_PORT|DATABASE_[A-Z_]+|MONGO_URL|REDIS_URL|POSTGRES_URL|TURSO_URL|LIBSQL_URL)\}/i,
  /^[ \t]*(DATABASE_URL|DATABASE_HOST|DATABASE_NAME|DATABASE_PORT|DATABASE_USER|DATABASE_PASSWORD|DB_HOST|DB_NAME|DB_PORT|DB_USER|DB_PASS|DB_PASSWORD|DB_URL|MONGO_URL|REDIS_URL|POSTGRES_URL|TURSO_URL|LIBSQL_URL)=/im,
