      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Empty repo — no DB config needed', findings: [] };
    }

    if (isDbDriverLibrary(packageJson)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: `DB driver library (${packageJson.name}) — not applicable`, findings: [] };
    }

    // 1. Discover DB deps across the monorepo (all package.json files)
    const pkgJsonPaths = tree
      .filter(p => p.endsWith('package.json') && !isExcludedPath(p) && !p.includes('node_modules'))
      .slice(0, 25);

    let hasDbDep = false;
    const dbPkgPaths = [];

    for (const p of pkgJsonPaths) {
      const content = await files.get(p);
      if (!content) continue;
      let pkg;
      try {
        pkg = JSON.parse(content);
      } catch {
        continue;
      }
      const deps = { ...pkg.dependencies, ...pkg.devDependencies };
      if (DB_DEPS.some(d => deps[d])) {
        hasDbDep = true;
        dbPkgPaths.push(p);
      }
    }

    // Fallback to the pre-parsed root package.json if it wasn't in tree (rare)
    if (!hasDbDep && packageJson) {
      const rootDeps = { ...packageJson.dependencies, ...packageJson.devDependencies };
      if (DB_DEPS.some(d => rootDeps[d])) {
        hasDbDep = true;
        dbPkgPaths.push('package.json');
      }
    }

    // 2. Identify strong config/schema indicators
    const strongFiles = tree.filter(p => isStrongIndicatorPath(p));
    const hasStrongIndicators = strongFiles.length > 0;

    // 3. If no DB usage signals at all, repo doesn't need this check
    if (!hasDbDep && !hasStrongIndicators) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'No database dependency or DB-related files found', findings: [] };
    }

    // Libraries without DB deps are unlikely to need DB deployment config
    if (repoType === 'library' && !hasDbDep) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Library — no DB config needed', findings: [] };
    }

    // 4. Build bounded scan list
    const scanSet = new Set();

    dbPkgPaths.forEach(p => scanSet.add(p));
    strongFiles.forEach(p => scanSet.add(p));

    // .env files (high signal, small)
    tree.filter(p => /(^|[\/])\.env/.test(p) && !isExcludedPath(p) && !/\.(test|spec|fixture)\.env$/i.test(p))
      .slice(0, 10)
      .forEach(p => scanSet.add(p));

    // DB-related source files when we know the repo uses a DB
    if (hasDbDep) {
      const dbSourceFiles = tree.filter(p => {
        if (scanSet.has(p)) return false;
        if (isExcludedPath(p)) return false;
        if (!/\.(js|ts|mjs|cjs)$/i.test(p)) return false;
        return /(^|[\/])(db|database|model|models|prisma|drizzle|config)[\/][^\\/]+\.(js|ts|mjs|cjs)$/i.test(p)
          || /(^|[\/])(db|database|connection|mongo|postgres|mysql|redis|sqlite|turso|libsql|client|pool)\.(js|ts|mjs|cjs)$/i.test(p);
      }).slice(0, 15);
      dbSourceFiles.forEach(p => scanSet.add(p));
    }

    const sourceFiles = Array.from(scanSet).slice(0, 40);

    let foundGood = false;
    let foundBad = false;
    const findings = [];

    for (const filePath of sourceFiles) {
      const content = await files.get(filePath);
      if (!content) continue;

      for (const pattern of GOOD_PATTERNS) {
        if (pattern.test(content)) {
          foundGood = true;
          const lines = content.split('\n');
          for (let i = 0; i < lines.length; i++) {
            if (pattern.test(lines[i])) {
              findings.push({ file: filePath, line: i + 1, issue: 'DB config uses environment variables' });
              break;
            }
          }
        }
      }

      const isEnvTemplate = /(^|[\/])\.env\./i.test(filePath);
      const isDockerCompose = /docker-compose/i.test(filePath);

      if (!isEnvTemplate && !isDockerCompose) {
        for (const pattern of BAD_PATTERNS) {
          const re = new RegExp(pattern.source, 'gmi');
