            count++;
            foundBad = true;
            const snippet = m[0].substring(0, 60);
            const lines = content.split('\n');
            for (let i = 0; i < lines.length; i++) {
              if (lines[i].includes(snippet)) {
                findings.push({ file: filePath, line: i + 1, issue: 'Hardcoded DB connection string with credentials' });
                break;
              }
            }
          }
        }
      }
    }

    if (foundBad) {
      return { checkId, status: 'fail', confidence: 'high', message: 'Hardcoded DB credentials detected', findings };
    }

    if (foundGood) {
      return { checkId, status: 'pass', confidence: 'high', message: 'DB configured with environment variables', findings };
    }

    // Definitive env-based config not found, but DB presence is real — check-it with findings
    const relevantFiles = [...dbPkgPaths, ...strongFiles].slice(0, 5);
    if (relevantFiles.length > 0) {
      return {
        checkId,
        status: 'check-it',
        confidence: 'medium',
        message: 'DB usage detected but could not verify environment-based configuration in scanned files',
        findings: relevantFiles.map(f => ({ file: f, issue: 'DB-related file found without clear env-based config pattern' }))
      };
    }

